const outsideClickDismissers = new Set();
let outsideClickDismissersWired = false;

function pruneOutsideClickDismissers() {
  outsideClickDismissers.forEach((entry) => {
    if (!entry || !entry.root || !entry.root.isConnected || typeof entry.onOutsideClick !== 'function') {
      if (entry && typeof entry.onDispose === 'function') {
        try {
          entry.onDispose();
        } catch (_err) {}
      }
      outsideClickDismissers.delete(entry);
    }
  });
}

function ensureOutsideClickDismissersWired() {
  if (outsideClickDismissersWired) return;
  document.addEventListener('click', (ev) => {
    pruneOutsideClickDismissers();
    outsideClickDismissers.forEach((entry) => {
      if (!entry || !entry.root || !entry.root.isConnected) return;
      if (entry.root.contains(ev.target)) return;
      const extraRoots = Array.isArray(entry.extraRoots) ? entry.extraRoots : [];
      if (extraRoots.some((root) => root && root.isConnected && root.contains(ev.target))) return;
      try {
        entry.onOutsideClick(ev);
      } catch (_err) {}
    });
  });
  outsideClickDismissersWired = true;
}

function registerOutsideClickDismiss(root, onOutsideClick, options) {
  if (!root || typeof onOutsideClick !== 'function') return;
  ensureOutsideClickDismissersWired();
  const opts = options || {};
  const entry = {
    root,
    onOutsideClick,
    extraRoots: Array.isArray(opts.extraRoots) ? opts.extraRoots.filter(Boolean) : [],
    onDispose: typeof opts.onDispose === 'function' ? opts.onDispose : null
  };
  outsideClickDismissers.add(entry);
}

function setPreviewCache(key, value) {
  const cacheKey = String(key || '');
  if (!cacheKey) return;
  if (state.previewCache.has(cacheKey)) state.previewCache.delete(cacheKey);
  state.previewCache.set(cacheKey, value);
  while (state.previewCache.size > getPreviewCacheLimit()) {
    const first = state.previewCache.keys().next();
    if (first && !first.done) state.previewCache.delete(first.value);
    else break;
  }
}

function clearPreviewCaches() {
  state.previewCache.clear();
  state.pendingPreviewRequests.clear();
}

function clearPreviewCacheEntries(predicate) {
  if (typeof predicate !== 'function') return;
  [state.previewCache, state.pendingPreviewRequests].forEach((cache) => {
    if (!cache || typeof cache.keys !== 'function' || typeof cache.delete !== 'function') return;
    for (const key of Array.from(cache.keys())) {
      if (predicate(String(key || ''))) cache.delete(key);
    }
  });
}

function getOrStartPreviewRequest(cacheKey, loader, options = {}) {
  const normalizedKey = String(cacheKey || '');
  if (normalizedKey && state.previewCache.has(normalizedKey)) {
    return Promise.resolve(state.previewCache.get(normalizedKey));
  }
  if (normalizedKey && state.pendingPreviewRequests.has(normalizedKey)) {
    return state.pendingPreviewRequests.get(normalizedKey);
  }
  const shouldCacheResult = options.cacheResult !== false;
  const shouldCacheFailure = options.cacheFailure === true;
  const request = Promise.resolve()
    .then(() => loader())
    .then((result) => {
      if (normalizedKey) state.pendingPreviewRequests.delete(normalizedKey);
      const isOk = !!(result && result.ok);
      if (normalizedKey && shouldCacheResult && (isOk || shouldCacheFailure)) {
        setPreviewCache(normalizedKey, result);
      }
      return result;
    })
    .catch((err) => {
      if (normalizedKey) state.pendingPreviewRequests.delete(normalizedKey);
      throw err;
    });
  if (normalizedKey) state.pendingPreviewRequests.set(normalizedKey, request);
  return request;
}

function setMapDistrictFallbackCanvas(key, canvas) {
  const cacheKey = String(key || '');
  if (!cacheKey || !canvas) return;
  if (state.biqMapDistrictFallbackCache.has(cacheKey)) state.biqMapDistrictFallbackCache.delete(cacheKey);
  state.biqMapDistrictFallbackCache.set(cacheKey, canvas);
  const limit = getPerformanceMode() === 'safe' ? 80 : 220;
  while (state.biqMapDistrictFallbackCache.size > limit) {
    const first = state.biqMapDistrictFallbackCache.keys().next();
    if (first && !first.done) state.biqMapDistrictFallbackCache.delete(first.value);
    else break;
  }
}

function getPerformanceMode() {
  const mode = String(state.settings && state.settings.performanceMode || DEFAULT_PERFORMANCE_MODE).toLowerCase();
  return mode === 'safe' ? 'safe' : 'high';
}

function getPreviewCacheLimit() {
  return getPerformanceMode() === 'safe' ? 220 : 700;
}

function getDefaultFrameSampleLimit() {
  return getPerformanceMode() === 'safe' ? 90 : 220;
}

function getPreviewScratchCanvas(width, height) {
  const w = Math.max(1, Number(width) || 1);
  const h = Math.max(1, Number(height) || 1);
  if (!previewScratch.canvas) {
    previewScratch.canvas = document.createElement('canvas');
    previewScratch.ctx = previewScratch.canvas.getContext('2d');
  }
  if (!previewScratch.ctx) return null;
  if (previewScratch.canvas.width !== w) previewScratch.canvas.width = w;
  if (previewScratch.canvas.height !== h) previewScratch.canvas.height = h;
  return previewScratch;
}

