function getFriendlyBiqSectionTitle(section) {
  const code = String((section && section.code) || '').toUpperCase();
  return BIQ_SECTION_FRIENDLY_NAMES[code] || String((section && section.title) || code || 'Section');
}

function getFallbackBiqSectionForOptions(sectionCode) {
  const code = String(sectionCode || '').toUpperCase();
  if (!state.bundle || !state.bundle.tabs) return null;
  const tabKeys = Object.keys(state.bundle.tabs);
  for (let i = 0; i < tabKeys.length; i += 1) {
    const tab = state.bundle.tabs[tabKeys[i]];
    const sections = Array.isArray(tab && tab.sections) ? tab.sections : [];
    const match = sections.find((section) => String(section && section.code || '').toUpperCase() === code);
    if (match) return match;
  }
  return null;
}

function makeBiqSectionIndexOptions(sectionCode, oneBased = false) {
  const code = String(sectionCode || '').toUpperCase();
  const biq = state.bundle && state.bundle.biq;
  const sections = biq && Array.isArray(biq.sections) ? biq.sections : [];
  const section = getFallbackBiqSectionForOptions(code)
    || sections.find((s) => String(s.code || '').toUpperCase() === code);
  const records = Array.isArray(section && section.fullRecords)
    ? section.fullRecords
    : (section && Array.isArray(section.records) ? section.records : []);
  const targetTabKey = BIQ_SECTION_TO_REFERENCE_TAB[code] || '';
  if ((!section || !Array.isArray(records) || records.length === 0) && targetTabKey) {
    const targetTab = state.bundle && state.bundle.tabs && state.bundle.tabs[targetTabKey];
    const targetEntries = targetTab && Array.isArray(targetTab.entries) ? targetTab.entries : [];
    return targetEntries.map((entry, idx) => {
      const entryIndex = getReferenceEntryIndexForOption(targetTabKey, entry, idx, { allowFallback: true });
      return {
        value: String(oneBased ? (entryIndex + 1) : entryIndex),
        label: String(entry && entry.name || `${code} ${idx + 1}`),
        entry,
        recIndex: entryIndex
      };
    }).filter((opt) => Number.isFinite(opt.recIndex) && opt.recIndex >= 0);
  }
  if (!section || !Array.isArray(records)) return [];
  const targetTab = targetTabKey && state.bundle && state.bundle.tabs && state.bundle.tabs[targetTabKey];
  const targetEntries = targetTab && Array.isArray(targetTab.entries) ? targetTab.entries : [];
  const entryByIndex = new Map();
  const entryByCivilopediaKey = new Map();
  const entryByName = new Map();
  targetEntries.forEach((entry, fallbackIdx) => {
    const biqIndex = getReferenceEntryIndexForOption(targetTabKey, entry, fallbackIdx);
    if (Number.isFinite(biqIndex) && biqIndex >= 0) entryByIndex.set(biqIndex, entry);
    const key = String(entry && entry.civilopediaKey || '').trim().toUpperCase();
    if (key) {
      const prior = entryByCivilopediaKey.get(key);
      if (!prior || (!prior.thumbPath && entry.thumbPath)) {
        entryByCivilopediaKey.set(key, entry);
      }
    }
    const nameKey = String(entry && entry.name || '').trim().toLowerCase();
    if (nameKey) {
      const priorByName = entryByName.get(nameKey);
      if (!priorByName || (!priorByName.thumbPath && entry.thumbPath)) {
        entryByName.set(nameKey, entry);
      }
    }
  });
  const rawOptions = records.map((rec, idx) => {
    const recIndex = Number.isFinite(rec && rec.index) ? Number(rec.index) : idx;
    const recCivilopediaKey = String(getFieldByBaseKey(rec, 'civilopediaentry')?.value || '').trim().toUpperCase();
    const recNameKey = String(rec && rec.name || '').trim().toLowerCase();
    const entry = entryByIndex.get(recIndex)
      || entryByCivilopediaKey.get(recCivilopediaKey)
      || entryByName.get(recNameKey)
      || (targetTabKey ? ensureSyntheticReferenceEntryForBiqRecord(targetTabKey, code, rec) : null)
      || null;
    const liveName = String(entry && entry.name || '').trim();
    const fallbackName = String(rec && rec.name || '').trim();
    const fallbackFromKey = recCivilopediaKey
      ? recCivilopediaKey
        .replace(/^[A-Z]+_/, '')
        .split('_')
        .filter(Boolean)
        .map((part) => part.charAt(0) + part.slice(1).toLowerCase())
        .join(' ')
      : '';
    // BIQ record names are the authoritative scenario-facing labels for BIQ structure refs.
    const label = fallbackName || liveName || fallbackFromKey || `${code} ${recIndex + 1}`;
    return {
      value: String(oneBased ? (recIndex + 1) : recIndex),
      label,
      entry,
      recIndex
    };
  });
  const labelCounts = new Map();
  rawOptions.forEach((opt) => {
    const k = String(opt && opt.label || '').trim().toLowerCase();
    if (!k) return;
    labelCounts.set(k, Number(labelCounts.get(k) || 0) + 1);
  });
  return rawOptions.map((opt) => {
    const key = String(opt && opt.label || '').trim().toLowerCase();
    const hasDup = key && Number(labelCounts.get(key) || 0) > 1;
    if (!hasDup) return { value: opt.value, label: opt.label, displayLabel: opt.label, entry: opt.entry };
    return {
      value: opt.value,
      label: `${opt.label} [ID ${opt.recIndex}]`,
      displayLabel: opt.label,
      entry: opt.entry
    };
  });
}

function isBarbarianCivilizationOption(opt) {
  const civId = Number.parseInt(String(opt && opt.value || ''), 10);
  if (civId === 0) return true;
  const civKey = String(opt && opt.entry && opt.entry.civilopediaKey || '').trim().toUpperCase();
  if (civKey === 'RACE_BARBARIANS') return true;
  const label = String(opt && (opt.displayLabel || opt.label) || '').trim().toLowerCase();
  return /barbarian/.test(label) || /^barbarians?$/.test(label);
}

function getBiqStructureRefSpec(sectionCode, baseKey) {
  const code = String(sectionCode || '').toUpperCase();
  const canon = String(baseKey || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  const unitRefKeys = new Set([
    'advancedbarbarian', 'basicbarbarian', 'barbarianseaunit', 'battlecreatedunit', 'buildarmyunit',
    'scout', 'slave', 'startunit1', 'startunit2', 'flagunit'
  ]);
  if ((code === 'GAME' || code === 'RULE') && unitRefKeys.has(canon)) return { section: 'PRTO', oneBased: false };
  if ((code === 'GAME' || code === 'RULE') && canon === 'defaultmoneyresource') return { section: 'GOOD', oneBased: false };
  if ((code === 'GAME' || code === 'RULE') && canon === 'defaultdifficultylevel') return { section: 'DIFF', oneBased: false };
  if (code === 'GAME' && canon.startsWith('playableciv')) return { section: 'RACE', oneBased: false };
  if (code === 'GAME' && canon === 'playableciv') return { section: 'RACE', oneBased: false };
  if (code === 'LEAD' && canon === 'civ') return { section: 'RACE', oneBased: false };
  if (code === 'LEAD' && canon === 'government') return { section: 'GOVT', oneBased: false };
  if (code === 'LEAD' && canon === 'initialera') return { section: 'ERAS', oneBased: false };
  if (code === 'LEAD' && /^startingtechnology\d+$/.test(canon)) return { section: 'TECH', oneBased: false };
  if (code === 'LEAD' && canon === 'difficulty') return { section: 'DIFF', oneBased: false };
  if (code === 'GOVT' && canon === 'immuneto') return { section: 'ESPN', oneBased: false };
  if (code === 'TFRM' && canon === 'requiredadvance') return { section: 'TECH', oneBased: false };
  if (code === 'TFRM' && (canon === 'requiredresource1' || canon === 'requiredresource2')) return { section: 'GOOD', oneBased: false };
  if (code === 'TERR' && canon === 'workerjob') return { section: 'TFRM', oneBased: false };
  if (code === 'TERR' && canon === 'pollutioneffect') return { section: 'TERR', oneBased: false };
  if (code === 'CTZN' && canon === 'prerequisite') return { section: 'TECH', oneBased: false };
  return null;
}

function getBiqStructureReferenceThumbRenderer(sectionCode, baseKey, refSpec) {
  const code = String(sectionCode || '').toUpperCase();
  const canon = String(baseKey || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  const targetSection = String(refSpec && refSpec.section || '').toUpperCase();
  if (code === 'TERR' && canon === 'pollutioneffect' && targetSection === 'TERR') {
    return ({ holder, option }) => renderTerrainReferenceThumb(
      holder,
      option && (option.displayLabel || option.label || option.value)
    );
  }
  if (code === 'TERR' && canon === 'workerjob' && targetSection === 'TFRM') {
    return ({ holder, option, value }) => {
      const workerIndex = Number.parseInt(String((option && option.value) || value || ''), 10);
      if (!Number.isFinite(workerIndex) || workerIndex < 0) return false;
      const fallbackEntry = option && option.entry;
      loadTfrmCommandButtonThumbnail({ index: workerIndex }, holder).then((ok) => {
        if (!ok && holder && holder.isConnected && fallbackEntry) {
          loadReferenceListThumbnail('workerActions', fallbackEntry, holder);
        }
      }).catch(() => {
        if (holder && holder.isConnected && fallbackEntry) {
          loadReferenceListThumbnail('workerActions', fallbackEntry, holder);
        }
      });
      return true;
    };
  }
  return null;
}

function getBiqStructureFieldSpec(sectionCode, field) {
  const code = String(sectionCode || '').toUpperCase();
  const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const schema = BIQ_STRUCTURE_RULE_SCHEMAS[code] || null;
  if (!schema || !schema.fields) return null;
  if (schema.fields[base]) return schema.fields[base];
  const canon = base.replace(/[^a-z0-9]/g, '');
  if (!canon) return null;
  const keys = Object.keys(schema.fields);
  for (let i = 0; i < keys.length; i += 1) {
    const key = String(keys[i] || '');
    if (key.replace(/[^a-z0-9]/g, '') === canon) return schema.fields[key];
  }
  return null;
}

function getLeadStartUnitDisplayLabel(field) {
  const baseKey = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const suffix = baseKey.replace(/^starting_units_of_type_/, '').trim();
  if (!suffix) return String(field && (field.label || field.key) || 'Starting Unit');
  const numericIndex = Number.parseInt(suffix, 10);
  if (Number.isFinite(numericIndex) && numericIndex >= 0) {
    const unitOptions = makeBiqSectionIndexOptions('PRTO', false);
    const match = unitOptions.find((opt) => Number.parseInt(String(opt && opt.value || ''), 10) === numericIndex);
    if (match && match.label) return `${match.label} Units`;
  }
  const unitName = suffix
    .replace(/_/g, ' ')
    .replace(/\b\w/g, (m) => m.toUpperCase());
  return unitName ? `${unitName} Units` : String(field && (field.label || field.key) || 'Starting Unit');
}

function parseLeadStartUnitFieldIndex(field) {
  const baseKey = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const match = baseKey.match(/^starting_units_of_type_(.+)$/);
  if (!match) return null;
  const suffix = String(match[1] || '').trim().toLowerCase();
  const numeric = Number.parseInt(suffix, 10);
  if (Number.isFinite(numeric) && numeric >= 0) return numeric;
  if (suffix === 'settler') return 0;
  if (suffix === 'worker') return 1;
  return null;
}

function getLeadStartUnitCount(field) {
  const parsed = Number.parseInt(String(field && field.value || '').trim(), 10);
  return Number.isFinite(parsed) ? Math.max(0, parsed) : 0;
}

function getLeadStartUnitFields(record) {
  return (Array.isArray(record && record.fields) ? record.fields : [])
    .filter((field) => parseLeadStartUnitFieldIndex(field) != null);
}

function makeLeadStartUnitField(unitIndex, amount = 1) {
  const idx = Math.max(0, Number.parseInt(String(unitIndex), 10) || 0);
  const baseKey = `starting_units_of_type_${idx}`;
  return {
    key: baseKey,
    baseKey,
    label: getSeedLeadFieldLabel(baseKey),
    value: String(Math.max(0, Number.parseInt(String(amount), 10) || 0)),
    originalValue: ''
  };
}

function ensureLeadStartUnitField(record, unitIndex, amount = 1) {
  if (!record) return null;
  if (!Array.isArray(record.fields)) record.fields = [];
  const idx = Number.parseInt(String(unitIndex), 10);
  if (!Number.isFinite(idx) || idx < 0) return null;
  const existing = getLeadStartUnitFields(record).find((field) => parseLeadStartUnitFieldIndex(field) === idx);
  if (existing) return existing;
  const created = makeLeadStartUnitField(idx, amount);
  const startFields = getLeadStartUnitFields(record);
  let insertAt = record.fields.length;
  if (startFields.length > 0) {
    const lastPos = record.fields.indexOf(startFields[startFields.length - 1]);
    if (lastPos >= 0) insertAt = lastPos + 1;
  } else {
    const countField = getFieldByBaseKey(record, 'numberofdifferentstartunits');
    const countPos = record.fields.indexOf(countField);
    if (countPos >= 0) insertAt = countPos + 1;
  }
  record.fields.splice(insertAt, 0, created);
  return created;
}

function getLeadStartUnitEntries(record) {
  const seen = new Set();
  return getLeadStartUnitFields(record)
    .map((field) => ({
      field,
      unitIndex: parseLeadStartUnitFieldIndex(field),
      amount: getLeadStartUnitCount(field)
    }))
    .filter((entry) => {
      if (!Number.isFinite(entry.unitIndex) || entry.unitIndex < 0 || entry.amount <= 0) return false;
      if (seen.has(entry.unitIndex)) return false;
      seen.add(entry.unitIndex);
      return true;
    });
}

function getBiqStructureDisplayLabel(sectionCode, field, groupFields, fieldIdx) {
  const code = String(sectionCode || '').toUpperCase();
  const baseKeyRaw = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const rawKey = String(field && (field.baseKey || field.key) || '');
  const rawLabel = String(field && (field.label || '') || '');
  if (code === 'GAME' && baseKeyRaw === 'playable_civ') {
    const playableIdx = (Array.isArray(groupFields) ? groupFields : [])
      .slice(0, Number(fieldIdx || 0) + 1)
      .filter((f) => String(f && (f.baseKey || f.key) || '').toLowerCase() === 'playable_civ')
      .length;
    return `Playable Civilization ${playableIdx}`;
  }
  if (code === 'LEAD' && /^starting_units_of_type_/.test(baseKeyRaw)) {
    return getLeadStartUnitDisplayLabel(field);
  }
  if (code === 'LEAD' && /^starting_technology_\d+$/.test(baseKeyRaw)) {
    const techIdx = Number.parseInt(baseKeyRaw.replace(/^starting_technology_/, ''), 10);
    if (Number.isFinite(techIdx)) return `Free Technology ${techIdx + 1}`;
  }
  const spec = getBiqStructureFieldSpec(sectionCode, field);
  if (spec && spec.label) return String(spec.label);
  if (rawLabel && rawLabel.toLowerCase() !== rawKey.toLowerCase()) return rawLabel;
  return toFriendlyKey(rawKey);
}

function getBiqStructureFieldGroup(sectionCode, field) {
  const code = String(sectionCode || '').toUpperCase();
  const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const canon = base.replace(/[^a-z0-9]/g, '');
  if (code === 'GAME') {
    if (/^playable_civ(_\d+)?$/.test(base)) return 'Player Options';
    if (/^turns_in_time_section_\d+$/.test(base) || /^time_per_turn_in_time_section_\d+$/.test(base) ||
        base === 'turns_per_timescale_part' || base === 'time_units_per_turn') return 'Time Scale';
    const allianceName = base.match(/^alliance(\d+)$/);
    if (allianceName) {
      const idx = Number.parseInt(allianceName[1], 10);
      if (idx === 0) return 'No Alliances';
      if (Number.isFinite(idx) && idx >= 1 && idx <= 4) return `Alliance ${idx}`;
      return 'Locked Alliances';
    }
    const allianceMember = base.match(/^alliance(\d+)_member_\d+$/);
    if (allianceMember) {
      const idx = Number.parseInt(allianceMember[1], 10);
      if (idx === 0) return 'No Alliances';
      if (Number.isFinite(idx) && idx >= 1 && idx <= 4) return `Alliance ${idx}`;
      return 'Locked Alliances';
    }
    const allianceWar = base.match(/^alliance(\d+)_is_at_war_with_alliance(\d+)_\d+$/);
    if (allianceWar) {
      const idx = Number.parseInt(allianceWar[1], 10);
      if (idx === 0) return 'No Alliances';
      if (Number.isFinite(idx) && idx >= 1 && idx <= 4) return `Alliance ${idx}`;
      return 'Locked Alliances';
    }
  }
  if (code === 'LEAD') {
    if (/^starting_units_of_type_/.test(base)) return 'Starting Units';
    if (/^starting_technolog/.test(base)) return 'Free Techs';
  }
  if (code === 'RULE') {
    if (/^number_of_parts_\d+_required$/.test(base)) return 'Spaceship Parts';
    if (/^cultural_level_\d+$/.test(base) || base === 'numculturelevels') return 'Culture Levels';
    if (/^questionmark(?:\d+|one|two|three|four)?$/.test(canon)) return 'Unknowns';
  }
  const spec = getBiqStructureFieldSpec(sectionCode, field);
  if (spec && spec.group) return spec.group;
  return 'Other';
}

function getBiqStructureFieldOrder(sectionCode, field) {
  const code = String(sectionCode || '').toUpperCase();
  const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const schema = BIQ_STRUCTURE_RULE_SCHEMAS[code] || null;
  if (code === 'GAME') {
    if (/^playable_civ(_\d+)?$/.test(base)) return 60;
    const turnsMatch = base.match(/^turns_in_time_section_(\d+)$/);
    if (turnsMatch) return 260 + Number.parseInt(turnsMatch[1], 10) * 2;
    const perMatch = base.match(/^time_per_turn_in_time_section_(\d+)$/);
    if (perMatch) return 261 + Number.parseInt(perMatch[1], 10) * 2;
    if (base === 'turns_per_timescale_part') return 260;
    if (base === 'time_units_per_turn') return 261;
    const allianceMemberMatch = base.match(/^alliance(\d+)_member_(\d+)$/);
    if (allianceMemberMatch) {
      const allianceIdx = Number.parseInt(allianceMemberMatch[1], 10);
      const memberIdx = Number.parseInt(allianceMemberMatch[2], 10);
      return 430 + allianceIdx * 20 + memberIdx;
    }
    const allianceWarMatch = base.match(/^alliance(\d+)_is_at_war_with_alliance(\d+)_\d+$/);
    if (allianceWarMatch) {
      const allianceIdx = Number.parseInt(allianceWarMatch[1], 10);
      const enemyIdx = Number.parseInt(allianceWarMatch[2], 10);
      return 520 + allianceIdx * 10 + enemyIdx;
    }
  }
  if (code === 'LEAD') {
    if (/^starting_units_of_type_/.test(base)) return 200;
    const techMatch = base.match(/^starting_technology_(\d+)$/);
    if (techMatch) return 300 + Number.parseInt(techMatch[1], 10);
  }
  if (code === 'RULE') {
    const partReqMatch = base.match(/^number_of_parts_(\d+)_required$/);
    if (partReqMatch) {
      const partIdx = Number.parseInt(partReqMatch[1], 10);
      if (Number.isFinite(partIdx)) return 300 + partIdx;
      return 300;
    }
    if (base === 'numculturelevels') return 330;
    const cultureLevelMatch = base.match(/^cultural_level_(\d+)$/);
    if (cultureLevelMatch) {
      const levelIdx = Number.parseInt(cultureLevelMatch[1], 10);
      if (Number.isFinite(levelIdx)) return 331 + levelIdx;
      return 331;
    }
  }
  if (!schema || !Array.isArray(schema.order)) return Number.MAX_SAFE_INTEGER;
  const idx = schema.order.indexOf(base);
  if (idx >= 0) return idx;
  const canon = base.replace(/[^a-z0-9]/g, '');
  if (!canon) return Number.MAX_SAFE_INTEGER;
  const canonIdx = schema.order.findIndex((key) => String(key || '').replace(/[^a-z0-9]/g, '') === canon);
  return canonIdx >= 0 ? canonIdx : Number.MAX_SAFE_INTEGER;
}

function parseEspionageMissionPerformedBy(value) {
  const parsed = parseIntFromDisplayValue(value);
  const raw = Number.isFinite(parsed) ? parsed : Number.parseInt(String(value || '').trim(), 10);
  if (!Number.isFinite(raw)) {
    const text = String(value || '').toLowerCase();
    return {
      diplomats: text.includes('diplomat'),
      spies: text.includes('spy')
    };
  }
  const mask = Math.max(0, Math.min(3, raw));
  return {
    diplomats: (mask & 1) !== 0,
    spies: (mask & 2) !== 0
  };
}

function formatEspionageMissionPerformedBy(value) {
  const stateValue = parseEspionageMissionPerformedBy(value);
  if (stateValue.diplomats && stateValue.spies) return 'Diplomats + Spies';
  if (stateValue.spies) return 'Spies';
  if (stateValue.diplomats) return 'Diplomats';
  return '(none)';
}

function shouldHideBiqStructureField(sectionCode, field) {
  const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
  const canon = base.replace(/[^a-z0-9]/g, '');
  if (!base) return true;
  if (BIQ_STRUCTURE_FIELD_HIDDEN.all.has(base) || BIQ_STRUCTURE_FIELD_HIDDEN.all.has(canon)) return true;
  const sectionHidden = BIQ_STRUCTURE_FIELD_HIDDEN[String(sectionCode || '').toUpperCase()];
  if (sectionHidden && (sectionHidden.has(base) || sectionHidden.has(canon))) return true;
  return false;
}

