function isLikelyBooleanField(field) {
  const raw = String(field && field.value || '').toLowerCase().trim();
  if (raw === 'true' || raw === 'false') return true;
  const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
  return base.startsWith('is') || base.startsWith('can') || base.startsWith('allow') || base.startsWith('enable') || base.startsWith('has');
}

function getBiqFieldByBaseKey(entry, baseKey) {
  const target = String(baseKey || '').toLowerCase();
  if (!entry || !Array.isArray(entry.biqFields) || !target) return null;
  return entry.biqFields.find((f) => String(f.baseKey || f.key || '').toLowerCase() === target) || null;
}

function parseCivilizationColorSlot(entry, baseKey) {
  const field = getBiqFieldByBaseKey(entry, baseKey);
  const parsed = parseIntFromDisplayValue(field && field.value);
  const rawParsed = parsed == null ? Number.parseInt(String(field && field.value || '').trim(), 10) : parsed;
  if (!Number.isFinite(rawParsed)) return null;
  return Math.max(0, Math.min(31, rawParsed));
}

function createCivilizationListColorChip(entry) {
  const defaultSlot = parseCivilizationColorSlot(entry, 'defaultcolor');
  const uniqueSlot = parseCivilizationColorSlot(entry, 'uniquecolor');
  if (defaultSlot == null && uniqueSlot == null) return null;
  const primarySlot = defaultSlot == null ? uniqueSlot : defaultSlot;
  const secondarySlot = uniqueSlot == null ? primarySlot : uniqueSlot;
  const chip = document.createElement('span');
  chip.className = 'civilization-list-color-chip';
  chip.style.setProperty('--civ-primary-color', getCivSlotUiColor(primarySlot, (css) => {
    if (chip.isConnected) chip.style.setProperty('--civ-primary-color', css);
  }));
  chip.style.setProperty('--civ-secondary-color', getCivSlotUiColor(secondarySlot, (css) => {
    if (chip.isConnected) chip.style.setProperty('--civ-secondary-color', css);
  }));
  if (primarySlot !== secondarySlot) chip.classList.add('split');
  chip.title = primarySlot === secondarySlot
    ? `Default Color ${primarySlot}`
    : `Default Color ${primarySlot} / Alternate Color ${secondarySlot}`;
  return chip;
}

function refreshCivilizationListColorChip(entry, baseIndex) {
  const listPane = el && el.tabContent ? el.tabContent.querySelector('.entry-list-pane') : null;
  if (!listPane || !entry) return;
  const entryIdentity = getReferenceEntryIdentity('civilizations', entry, baseIndex);
  const itemBtn = Array.from(listPane.querySelectorAll('.entry-list-item[data-entry-id]'))
    .find((node) => node.getAttribute('data-entry-id') === entryIdentity);
  if (!itemBtn) return;
  Array.from(itemBtn.querySelectorAll('.civilization-list-color-chip')).forEach((node) => node.remove());
  const colorChip = createCivilizationListColorChip(entry);
  if (colorChip) {
    itemBtn.appendChild(colorChip);
    itemBtn.title = colorChip.title;
  } else {
    itemBtn.removeAttribute('title');
  }
}

function ensureBiqFieldByBaseKey(entry, baseKey, label = '', initialValue = '') {
  const target = String(baseKey || '').toLowerCase();
  if (!entry || !target) return null;
  let field = getBiqFieldByBaseKey(entry, target);
  if (field) return field;
  if (!Array.isArray(entry.biqFields)) entry.biqFields = [];
  field = {
    key: target,
    baseKey: target,
    label: label || toFriendlyKey(target),
    value: String(initialValue || ''),
    originalValue: '',
    editable: true
  };
  entry.biqFields.push(field);
  return field;
}

function buildIdentityTechContext(tabKey, entry) {
  const ctx = {
    label: 'Tech Notes',
    values: Array.isArray(entry && entry.techDependencies) ? entry.techDependencies : [],
    fields: [],
    editable: false
  };
  if (!entry || !Array.isArray(entry.biqFields)) return ctx;
  if (tabKey === 'civilizations') {
    const keys = ['freetech1index', 'freetech2index', 'freetech3index', 'freetech4index'];
    const fields = keys.map((k) => getBiqFieldByBaseKey(entry, k)).filter(Boolean);
    ctx.label = 'Starting Techs';
    ctx.fields = fields;
    ctx.values = fields.map((f) => String(f.value || '').trim()).filter((v) => v && !/^none$/i.test(v) && v !== '-1');
    ctx.editable = fields.some((f) => !!f.editable);
    return ctx;
  }
  if (tabKey === 'technologies') {
    const keys = ['prerequisite1', 'prerequisite2', 'prerequisite3', 'prerequisite4'];
    const fields = keys.map((k) => getBiqFieldByBaseKey(entry, k)).filter(Boolean);
    ctx.label = 'Prerequisite Techs';
    ctx.fields = fields;
    ctx.values = fields.map((f) => String(f.value || '').trim()).filter((v) => v && !/^none$/i.test(v) && v !== '-1');
    ctx.editable = fields.some((f) => !!f.editable);
    return ctx;
  }
  if (tabKey === 'resources') {
    const f = getBiqFieldByBaseKey(entry, 'prerequisite');
    if (f) {
      ctx.label = 'Required Tech';
      ctx.fields = [f];
      ctx.values = String(f.value || '').trim() && !/^none$/i.test(String(f.value || '')) ? [String(f.value || '').trim()] : [];
      ctx.editable = !!f.editable;
    }
    return ctx;
  }
  if (tabKey === 'improvements') {
    ctx.values = [];
    return ctx;
  }
  if (tabKey === 'units') {
    const f = getBiqFieldByBaseKey(entry, 'requiredtech');
    if (f) {
      ctx.label = 'Required Tech';
      ctx.fields = [f];
      ctx.values = String(f.value || '').trim() && !/^none$/i.test(String(f.value || '')) ? [String(f.value || '').trim()] : [];
      ctx.editable = !!f.editable;
    }
    return ctx;
  }
  if (tabKey === 'governments') {
    const f = getBiqFieldByBaseKey(entry, 'prerequisitetechnology');
    if (f) {
      ctx.label = 'Required Tech';
      ctx.fields = [f];
      ctx.values = String(f.value || '').trim() && !/^none$/i.test(String(f.value || '')) ? [String(f.value || '').trim()] : [];
      ctx.editable = !!f.editable;
    }
    return ctx;
  }
  return ctx;
}

function formatIdentityTechValues(techCtx) {
  if (!techCtx || !Array.isArray(techCtx.fields) || techCtx.fields.length === 0) {
    return Array.isArray(techCtx && techCtx.values) ? techCtx.values : [];
  }
  return techCtx.fields
    .map((field) => {
      const idx = resolveTechIndexFromValue(field.value);
      return idx == null || idx < 0 ? '' : getTechLabelByIndex(idx);
    })
    .filter(Boolean);
}

function createTechIdentityPicker(field, onChange, undoKey = '') {
  const techOptions = getTechEntries().map((tech, fallbackIdx) => ({
    value: String(getReferenceEntryIndexForOption('technologies', tech, fallbackIdx, { allowFallback: true })),
    label: String(tech.name || ''),
    entry: tech
  }));
  const entryUndoKey = String(undoKey || '').trim();
  const parsedCurrent = resolveTechIndexFromValue(field && field.value);
  return createReferencePicker({
    options: techOptions,
    targetTabKey: 'technologies',
    currentValue: parsedCurrent == null ? '-1' : String(parsedCurrent),
    searchPlaceholder: 'Search tech...',
    noneLabel: '(none)',
    onSelect: (value, option) => {
      if (entryUndoKey) rememberUndoSnapshotForKey(entryUndoKey);
      else rememberUndoSnapshot();
      field.value = String(value);
      setFieldReferenceTargetMeta(field, 'technologies', option, value, techOptions);
      if (onChange) onChange();
    }
  });
}

const TECH_TREE_ERA_BACKGROUND_CANDIDATES = {
  0: ['Art/Advisors/science_ancient.pcx'],
  1: ['Art/Advisors/science_middle.pcx'],
  2: ['Art/Advisors/science_industrial_new.pcx', 'Art/Advisors/science_industrial.pcx'],
  3: ['Art/Advisors/science_modern.pcx']
};
const TECH_TREE_TECHBOX_CANDIDATES = ['Art/Advisors/techboxes.pcx'];
const TECH_TREE_ADVISOR_FACE_CANDIDATES = ['Art/SmallHeads/popupSCIENCE.pcx'];
const TECH_TREE_ADVISOR_DIALOG_CANDIDATES = ['Art/Advisors/dialogbox.pcx'];
const TECH_TREE_ARROW_METADATA_RELATIVE_PATH = 'c3x_editor_tech_tree_arrows.json';
const TECH_TREE_NON_ERA_GUTTER_WIDTH = 220;
const TECH_TREE_NON_ERA_GUTTER_LEFT = 18;
const TECH_TREE_NON_ERA_MIN_VERTICAL_GAP = 14;
const TECH_TREE_ERA_PANE_LEFT_PADDING = 28;
const TECH_TREE_STAGE_SIDE_PADDING = 24;
const TECH_TREE_GAME_BOX_RENDER_Y_OFFSET = 4;
const TECH_TREE_ADVISOR_FACE_CELL_SIZE = 150;
const TECH_TREE_ADVISOR_FACE_X = 846;
const TECH_TREE_ADVISOR_FACE_Y = -42;
const TECH_TREE_ADVISOR_DIALOG_X = 802;
const TECH_TREE_ADVISOR_DIALOG_Y = 108;
const TECH_TREE_ARROW_FRAME_WARNING_TEXT = 'Warning: arrow may be permanently drawn on border';
const TECH_TREE_ARROW_FRAME_WARNING_MARGIN = 6;
const TECH_TREE_ARROW_FRAME_GUIDE_DASH = [8, 5];

function getTechTreeArrowFrameWarningNoteForEra(eraIndex) {
  const key = String(Number(eraIndex) || 0);
  const entry = state.techTreeArrowFrameWarningsByEra && state.techTreeArrowFrameWarningsByEra[key];
  const count = Number(entry && entry.count);
  return count > 0 ? TECH_TREE_ARROW_FRAME_WARNING_TEXT : '';
}

async function loadTechTreeAdvisorOverlayPreviews() {
  const loadCandidate = async (candidates, options = {}) => {
    for (const assetPath of candidates) {
      try {
        const res = await window.c3xManager.getPreview({
          kind: 'civilopediaIcon',
          civ3Path: state.settings.civ3Path,
          scenarioPath: state.settings.scenarioPath,
          scenarioPaths: getScenarioPreviewPaths(),
          assetPath,
          options
        });
        if (res && res.ok) return res;
      } catch (_err) {
        // Try next candidate.
      }
    }
    return null;
  };
  const [face, dialog] = await Promise.all([
    loadCandidate(TECH_TREE_ADVISOR_FACE_CANDIDATES, { transparentIndexes: [254, 255] }),
    loadCandidate(TECH_TREE_ADVISOR_DIALOG_CANDIDATES, { transparentIndexes: [] })
  ]);
  return { face, dialog };
}

function renderTechTreeAdvisorOverlay(layer, previews, eraValue, baseX, baseY, baseW, baseH) {
  if (!layer) return;
  layer.innerHTML = '';
  const facePreview = previews && previews.face;
  const dialogPreview = previews && previews.dialog;
  if (!facePreview && !dialogPreview) return;
  const scaleX = Math.max(0.01, (Number(baseW) || 1024) / 1024);
  const scaleY = Math.max(0.01, (Number(baseH) || 768) / 768);
  const place = (canvas, x, y, w = canvas.width, h = canvas.height) => {
    canvas.style.left = `${Math.round((Number(baseX) || 0) + (x * scaleX))}px`;
    canvas.style.top = `${Math.round((Number(baseY) || 0) + (y * scaleY))}px`;
    canvas.style.width = `${Math.max(1, Math.round(w * scaleX))}px`;
    canvas.style.height = `${Math.max(1, Math.round(h * scaleY))}px`;
  };
  if (facePreview) {
    const faceCanvas = document.createElement('canvas');
    faceCanvas.className = 'tech-tree-advisor-face';
    const eraIndex = Math.max(0, Math.min(3, Number.parseInt(String(eraValue), 10) || 0));
    const cellSize = TECH_TREE_ADVISOR_FACE_CELL_SIZE;
    if (drawPreviewCropToCanvas(facePreview, faceCanvas, {
      x: 0,
      y: eraIndex * cellSize,
      w: cellSize,
      h: cellSize
    })) {
      place(faceCanvas, TECH_TREE_ADVISOR_FACE_X, TECH_TREE_ADVISOR_FACE_Y, cellSize, cellSize);
      layer.appendChild(faceCanvas);
    }
  }
  if (dialogPreview) {
    const dialogCanvas = document.createElement('canvas');
    dialogCanvas.className = 'tech-tree-advisor-dialog';
    if (drawPreviewCropToCanvas(dialogPreview, dialogCanvas)) {
      place(dialogCanvas, TECH_TREE_ADVISOR_DIALOG_X, TECH_TREE_ADVISOR_DIALOG_Y, dialogCanvas.width, dialogCanvas.height);
      layer.appendChild(dialogCanvas);
    }
  }
}

function getEraOptionsForTechTree() {
  const fromBiq = makeBiqSectionIndexOptions('ERAS', false);
  if (Array.isArray(fromBiq) && fromBiq.length > 0) {
    return fromBiq.map((opt, idx) => ({
      value: String(opt.value),
      label: String(opt.label || `Era ${idx + 1}`)
    }));
  }
  const fallback = ['Ancient Times', 'Middle Ages', 'Industrial Age', 'Modern Times'];
  return fallback.map((name, idx) => ({ value: String(idx), label: name }));
}

function getTechField(entry, baseKey) {
  return getBiqFieldByBaseKey(entry, baseKey);
}

function getTechFieldInt(entry, baseKey, fallback = -1) {
  const field = getTechField(entry, baseKey);
  const n = parseIntFromDisplayValue(field && field.value);
  return (n == null) ? fallback : n;
}

function getTechPrereqFields(entry) {
  const fields = Array.isArray(entry && entry.biqFields) ? entry.biqFields : [];
  const keyed = fields.filter((field) => {
    const base = String(field && (field.baseKey || '')).toLowerCase();
    const key = String(field && (field.key || '')).toLowerCase();
    if (base === 'prerequisite' || base.startsWith('prerequisite')) return true;
    if (key === 'prerequisite' || key.startsWith('prerequisite')) return true;
    return false;
  });
  keyed.sort((a, b) => {
    const ak = String((a && a.key) || '').toLowerCase();
    const bk = String((b && b.key) || '').toLowerCase();
    const ai = Number.parseInt((ak.match(/(\d+)$/) || [])[1] || '0', 10) || 0;
    const bi = Number.parseInt((bk.match(/(\d+)$/) || [])[1] || '0', 10) || 0;
    if (ai !== bi) return ai - bi;
    return ak.localeCompare(bk);
  });
  return keyed.slice(0, 4);
}

function getTechEraValue(entry, fallback = -1) {
  return getTechFieldInt(entry, 'era', fallback);
}

function isTechHiddenFromTree(entry) {
  return getTechEraValue(entry, -1) < 0;
}

function getCivilizationEntries() {
  const civTab = state.bundle && state.bundle.tabs && state.bundle.tabs.civilizations;
  return civTab && Array.isArray(civTab.entries) ? civTab.entries : [];
}

function getCivilizationTechTreeFilterOptions() {
  return makeBiqSectionIndexOptions('RACE', false)
    .filter((opt) => !isBarbarianCivilizationOption(opt))
    .map((opt) => ({
      value: String(opt.value),
      label: String(opt.displayLabel || opt.label || `Civilization ${opt.value}`),
      entry: opt.entry || null
    }));
}

function getCivilizationFreeTechIds(civEntry) {
  if (!civEntry) return [];
  const keys = ['freetech1index', 'freetech2index', 'freetech3index', 'freetech4index'];
  return keys
    .map((key) => getBiqFieldByBaseKey(civEntry, key))
    .map((field) => {
      const raw = field && field.value;
      const resolved = resolveTechIndexFromValue(raw);
      if (resolved != null) return resolved;
      const match = String(raw || '').match(/\((\d+)\)\s*$/);
      return match ? Number.parseInt(match[1], 10) : null;
    })
    .filter((value, idx, arr) => value >= 0 && arr.indexOf(value) === idx);
}

function ensureTechField(entry, baseKey, label, initialValue = '0') {
  if (!entry) return null;
  let field = getTechField(entry, baseKey);
  if (field) return field;
  if (!Array.isArray(entry.biqFields)) entry.biqFields = [];
  field = {
    key: baseKey,
    baseKey,
    label: label || baseKey,
    value: String(initialValue),
    editable: true
  };
  entry.biqFields.push(field);
  return field;
}

function setTechFieldInt(entry, baseKey, label, value) {
  const field = ensureTechField(entry, baseKey, label, '0');
  if (!field) return;
  field.value = String(Number.isFinite(value) ? Math.round(value) : 0);
}

function ensureTechPrereqFieldAt(entry, slotIndex) {
  const idx = Math.max(0, Math.min(3, Number(slotIndex) || 0));
  const fields = getTechPrereqFields(entry);
  if (fields[idx]) return fields[idx];
  if (!entry) return null;
  if (!Array.isArray(entry.biqFields)) entry.biqFields = [];
  const suffix = entry.biqFields.filter((f) => {
    const k = String((f && (f.key || f.baseKey)) || '').toLowerCase();
    return k.startsWith('prerequisite');
  }).length + 1;
  const field = {
    key: suffix === 1 ? 'prerequisite' : `prerequisite_${suffix}`,
    baseKey: 'prerequisite',
    label: `Prerequisite ${suffix}`,
    value: '-1',
    editable: true
  };
  entry.biqFields.push(field);
  return field;
}

function getTechTreeData(entries) {
  const list = Array.isArray(entries) ? entries : [];
  const nodes = list.map((entry, fallbackIdx) => {
    const id = getReferenceEntryIndexForOption('technologies', entry, fallbackIdx, { allowFallback: true });
    const era = getTechEraValue(entry, -1);
    const x = Math.max(0, getTechFieldInt(entry, 'x', 0));
    const y = Math.max(0, getTechFieldInt(entry, 'y', 0));
    const prereqs = getTechPrereqFields(entry)
      .map((field) => resolveTechIndexFromValue(field && field.value))
      .filter((v, idx, arr) => v >= 0 && arr.indexOf(v) === idx);
    return {
      id,
      era,
      x,
      y,
      prereqs,
      entry,
      index: fallbackIdx
    };
  });
  const byId = new Map();
  nodes.forEach((node) => byId.set(node.id, node));
  const dependents = new Map();
  nodes.forEach((node) => {
    node.prereqs.forEach((pre) => {
      if (!dependents.has(pre)) dependents.set(pre, []);
      dependents.get(pre).push(node.id);
    });
  });
  return { nodes, byId, dependents };
}

function isTechNotRequiredForEraAdvancement(entry) {
  const field = getTechField(entry, 'notrequiredforadvancement');
  const raw = String(field && field.value != null ? field.value : '').trim().toLowerCase();
  return raw === 'true' || raw === '1' || raw === 'yes';
}

const TECH_TREE_TECHBOX_UNLOCK_GROUP_KEYS = new Set(['units', 'improvements', 'workerJobs', 'obsoleteImprovements']);

function getTechTreeBoxIconCount(node, unitCivFilter = null) {
  if (!node) return 1;
  return 1 + getTechTreeBoxUnlockItems(node, unitCivFilter).length;
}

function getTechTreeUnitAvailableToIndices(entry) {
  const field = getBiqFieldByBaseKey(entry, 'availableto');
  return new Set(decodeAvailableToIndices(field && field.value).map((value) => Number(value)));
}

function shouldShowUnitInTechTreeBox(entry, unitCivFilter = null) {
  if (!entry || !isCountableReferenceEntry('units', entry)) return false;
  const availableTo = getTechTreeUnitAvailableToIndices(entry);
  if (availableTo.size === 0) return false;
  const rawSelectedCivIndex = unitCivFilter && unitCivFilter.selectedCivIndex;
  const selectedCivIndex = rawSelectedCivIndex == null || rawSelectedCivIndex === '' ? NaN : Number(rawSelectedCivIndex);
  if (Number.isFinite(selectedCivIndex) && selectedCivIndex >= 0) {
    return availableTo.has(selectedCivIndex);
  }
  const generalCivIndices = Array.isArray(unitCivFilter && unitCivFilter.generalCivIndices)
    ? unitCivFilter.generalCivIndices
      .map((value) => Number(value))
      .filter((value) => Number.isFinite(value) && value >= 0)
    : [];
  if (generalCivIndices.length === 0) return true;
  return generalCivIndices.every((idx) => availableTo.has(idx));
}

function getTechTreeBoxUnlockItems(node, unitCivFilter = null) {
  if (!node) return [];
  const items = [];
  TECHNOLOGY_UNLOCK_GROUPS.forEach((spec) => {
    if (!TECH_TREE_TECHBOX_UNLOCK_GROUP_KEYS.has(String(spec && spec.key || ''))) return;
    let selected = [];
    try {
      selected = getTechnologyUnlockSelectedEntries(spec, node.id, node.entry);
    } catch (_err) {
      selected = [];
    }
    selected.forEach((item) => {
      if (isTechnologyUnlockBiqStructureGroup(spec)) {
        const thumbEntry = getTechnologyUnlockBiqStructureThumbnailEntry(spec, item && item.entry);
        if (thumbEntry) {
          items.push({ tabKey: 'workerActions', entry: thumbEntry, commandButtonRecord: item.entry || null });
        }
        return;
      }
      if (item && item.entry && spec.tabKey) {
        if (String(spec.key || '') === 'units' && !shouldShowUnitInTechTreeBox(item.entry, unitCivFilter)) return;
        items.push({
          tabKey: spec.tabKey,
          entry: item.entry,
          obsolete: String(spec.key || '') === 'obsoleteImprovements'
        });
      }
    });
  });
  return items;
}

function getTechTreeBoxSizeIndex(node, unitCivFilter = null) {
  const count = getTechTreeBoxIconCount(node, unitCivFilter);
  if (techBoxLayout && typeof techBoxLayout.chooseTechBoxSizeIndexForIconCount === 'function') {
    return techBoxLayout.chooseTechBoxSizeIndexForIconCount(count);
  }
  if (count <= 2) return 0;
  if (count <= 4) return 1;
  if (count === 5) return 3;
  if (count <= 7) return 2;
  return 3;
}

function getTechTreeBoxTopRowIconCapacity(frame, iconCount) {
  const count = Math.max(1, Number(iconCount) || 1);
  const sizeIndex = Number(frame && frame.sizeIndex);
  if (sizeIndex === 0) return Math.min(2, count);
  if (sizeIndex === 1 || sizeIndex === 2) return Math.min(4, count);
  if (sizeIndex === 3) return Math.min(5, count);
  const width = Math.max(1, Number(frame && frame.w) || 1);
  return Math.max(1, Math.min(count, Math.floor(width / 32)));
}

function appendTechTreeIconRowPlaceholders(row, count) {
  const n = Math.max(0, Number(count) || 0);
  for (let i = 0; i < n; i += 1) {
    const spacer = document.createElement('span');
    spacer.className = 'tech-tree-node-icon-spacer';
    row.appendChild(spacer);
  }
}

function getTechBoxPreviewRgba(techBoxPreview) {
  if (!techBoxPreview || !techBoxPreview.rgbaBase64) return null;
  if (!techBoxPreview._cachedRgbaBytes) {
    techBoxPreview._cachedRgbaBytes = fromBase64ToUint8(techBoxPreview.rgbaBase64);
  }
  return techBoxPreview._cachedRgbaBytes;
}

function buildTechBoxLayoutFromPreview(techBoxPreview) {
  if (!techBoxLayout || typeof techBoxLayout.parseTechBoxSheetLayout !== 'function') return null;
  if (!techBoxPreview || !techBoxPreview.width || !techBoxPreview.height || !techBoxPreview.rgbaBase64) return null;
  if (techBoxPreview._cachedTechBoxLayout) return techBoxPreview._cachedTechBoxLayout;
  const rgba = getTechBoxPreviewRgba(techBoxPreview);
  if (!rgba) return null;
  techBoxPreview._cachedTechBoxLayout = techBoxLayout.parseTechBoxSheetLayout({
    width: Number(techBoxPreview.width),
    height: Number(techBoxPreview.height),
    rgba
  });
  return techBoxPreview._cachedTechBoxLayout;
}

function getTechTreeBoxFrame(techBoxPreview, eraValue, node, unitCivFilter = null) {
  if (!techBoxLayout || typeof techBoxLayout.getTechBoxFrame !== 'function') return null;
  const layout = buildTechBoxLayoutFromPreview(techBoxPreview);
  if (!layout) return null;
  return techBoxLayout.getTechBoxFrame(layout, eraValue, getTechTreeBoxSizeIndex(node, unitCivFilter), layout.defaultColumnIndex);
}

function getTechTreeGameBoxRenderYOffset(node) {
  return node && node.autoLayout ? 0 : TECH_TREE_GAME_BOX_RENDER_Y_OFFSET;
}

function getTechTreeDisplayYFromStoredY(storedY, baseY = 0, node = null) {
  return (Number(baseY) || 0) + (Number(storedY) || 0) + getTechTreeGameBoxRenderYOffset(node);
}

function getTechTreeStoredYFromDisplayY(displayY, baseY = 0, node = null) {
  return Math.max(0, (Number(displayY) || 0) - (Number(baseY) || 0) - getTechTreeGameBoxRenderYOffset(node));
}

function getTechTreeAutoLayoutSourceCoordinate(entry, baseKey, fallback) {
  const field = getTechField(entry, baseKey);
  const original = parseIntFromDisplayValue(field && field.originalValue);
  if (original != null) return Math.max(0, original);
  const value = parseIntFromDisplayValue(field && field.value);
  if (value != null) return Math.max(0, value);
  return Math.max(0, Number(fallback) || 0);
}

function getTechTreeAdvisorFaceExclusionZones(nativeW, nativeH) {
  const width = Math.max(1, Number(nativeW) || 1024);
  const height = Math.max(1, Number(nativeH) || 768);
  if (scienceAdvisorArrows && typeof scienceAdvisorArrows.getScienceAdvisorFrameInnerLayoutArea === 'function') {
    const area = scienceAdvisorArrows.getScienceAdvisorFrameInnerLayoutArea(width, height);
    return Array.isArray(area && area.exclusionZones) ? area.exclusionZones : [];
  }
  const left = Math.max(0, Math.floor(width - Math.max(216, width * 0.21)));
  const bottom = Math.min(height, Math.ceil(Math.max(260, height * 0.35)));
  return [{ x: left, y: 0, w: width - left, h: bottom }];
}

function getTechTreeAdvisorFrameLayoutArea(nativeW, nativeH) {
  const width = Math.max(1, Number(nativeW) || 1024);
  const height = Math.max(1, Number(nativeH) || 768);
  if (scienceAdvisorArrows && typeof scienceAdvisorArrows.getScienceAdvisorFrameInnerLayoutArea === 'function') {
    const area = scienceAdvisorArrows.getScienceAdvisorFrameInnerLayoutArea(width, height);
    const bounds = area && area.bounds;
    if (bounds && Number(bounds.w) > 0 && Number(bounds.h) > 0) {
      return {
        bounds: {
          x: Math.max(0, Number(bounds.x) || 0),
          y: Math.max(0, Number(bounds.y) || 0),
          w: Math.max(1, Number(bounds.w) || 1),
          h: Math.max(1, Number(bounds.h) || 1)
        },
        exclusionZones: Array.isArray(area.exclusionZones) ? area.exclusionZones : []
      };
    }
  }
  const innerBottom = Math.max(1, Math.min(height, Math.floor(height - Math.max(88, height * 0.115))));
  return {
    bounds: {
      x: 64,
      y: 56,
      w: Math.max(1, width - 128),
      h: Math.max(1, innerBottom - 56)
    },
    exclusionZones: getTechTreeAdvisorFaceExclusionZones(width, height)
  };
}

function getTechTreeArrowRouteConstraintArea(nativeW, nativeH, offsetX = 0, offsetY = 0) {
  const area = getTechTreeAdvisorFrameLayoutArea(nativeW, nativeH);
  const dx = Number(offsetX) || 0;
  const dy = Number(offsetY) || 0;
  const bounds = area && area.bounds ? area.bounds : { x: 0, y: 0, w: Math.max(1, Number(nativeW) || 1024), h: Math.max(1, Number(nativeH) || 768) };
  return {
    bounds: {
      x: (Number(bounds.x) || 0) + dx,
      y: (Number(bounds.y) || 0) + dy,
      w: Math.max(1, Number(bounds.w) || 1),
      h: Math.max(1, Number(bounds.h) || 1)
    },
    exclusionZones: (Array.isArray(area && area.exclusionZones) ? area.exclusionZones : []).map((zone) => ({
      x: (Number(zone && zone.x) || 0) + dx,
      y: (Number(zone && zone.y) || 0) + dy,
      w: Math.max(1, Number(zone && (zone.w || zone.width)) || 1),
      h: Math.max(1, Number(zone && (zone.h || zone.height)) || 1)
    })),
    margin: 10
  };
}

function getTechTreeAutoLayoutBounds(nodes, techBoxPreview, eraValue, nativeW, nativeH) {
  const list = Array.isArray(nodes) ? nodes : [];
  const width = Math.max(1, Number(nativeW) || 1024);
  const height = Math.max(1, Number(nativeH) || 768);
  const frameArea = getTechTreeAdvisorFrameLayoutArea(width, height);
  const frameBounds = frameArea.bounds;
  let minX = Number.POSITIVE_INFINITY;
  let minY = Number.POSITIVE_INFINITY;
  let maxRight = 0;
  let maxBottom = 0;
  list.forEach((node) => {
    if (!node || !node.entry) return;
    const frame = getTechTreeBoxFrame(techBoxPreview, eraValue, node, null);
    const w = frame ? Math.max(1, Number(frame.w) || 136) : 136;
    const h = frame ? Math.max(1, Number(frame.h) || 64) : 64;
    const x = getTechTreeAutoLayoutSourceCoordinate(node.entry, 'x', node.x);
    const y = getTechTreeDisplayYFromStoredY(getTechTreeAutoLayoutSourceCoordinate(node.entry, 'y', node.y), 0, node);
    minX = Math.min(minX, x);
    minY = Math.min(minY, y);
    maxRight = Math.max(maxRight, x + w);
    maxBottom = Math.max(maxBottom, y + h);
  });
  const fallback = {
    x: frameBounds.x,
    y: frameBounds.y,
    w: frameBounds.w,
    h: frameBounds.h,
    exclusionZones: frameArea.exclusionZones
  };
  if (!Number.isFinite(minX) || !Number.isFinite(minY)) return fallback;
  const frameRight = frameBounds.x + frameBounds.w;
  const frameBottom = frameBounds.y + frameBounds.h;
  const left = Math.max(frameBounds.x, Math.min(frameRight - 1, Math.floor(minX)));
  const top = Math.max(frameBounds.y, Math.min(frameBottom - 1, Math.floor(minY)));
  const right = Math.max(left + 1, Math.min(frameRight, Math.ceil(maxRight)));
  const bottom = Math.max(top + 1, Math.min(frameBottom, Math.ceil(maxBottom)));
  const bounds = { x: left, y: top, w: right - left, h: bottom - top };
  bounds.exclusionZones = frameArea.exclusionZones;
  if (bounds.w < frameBounds.w * 0.45 || bounds.h < frameBounds.h * 0.45) {
    return fallback;
  }
  return bounds;
}

function drawTechTreeBoxFrame(techBoxPreview, frame, canvas) {
  if (!techBoxPreview || !frame || !canvas) return false;
  const sheet = rgbaToCanvas(techBoxPreview);
  const ctx = canvas.getContext('2d');
  if (!sheet || !ctx) return false;
  canvas.width = Math.max(1, Number(frame.w) || 1);
  canvas.height = Math.max(1, Number(frame.h) || 1);
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.imageSmoothingEnabled = false;
  ctx.drawImage(sheet, frame.x, frame.y, frame.w, frame.h, 0, 0, canvas.width, canvas.height);
  return true;
}

function getReachableTechIdsForCivilization(nodes, civEntry) {
  const reachable = new Set();
  const civFreeTechs = getCivilizationFreeTechIds(civEntry);
  civFreeTechs.forEach((id) => {
    if (id >= 0) reachable.add(id);
  });
  nodes.forEach((node) => {
    if (!node || isTechHiddenFromTree(node.entry)) return;
    if (!Array.isArray(node.prereqs) || node.prereqs.length === 0) reachable.add(node.id);
  });
  let changed = true;
  while (changed) {
    changed = false;
    nodes.forEach((node) => {
      if (!node || reachable.has(node.id)) return;
      if (!Array.isArray(node.prereqs) || node.prereqs.length === 0) return;
      if (node.prereqs.every((pre) => reachable.has(pre))) {
        reachable.add(node.id);
        changed = true;
      }
    });
  }
  return reachable;
}

function summarizeTechTreeNodeForDebug(node) {
  if (!node) return '(null)';
  const name = String(node.entry && node.entry.name || `Tech ${node.id}`);
  const parts = [
    `id=${node.id}`,
    `name=${name}`,
    `era=${node.era}`,
    `x=${Number.isFinite(node.x) ? node.x : '?'}`,
    `y=${Number.isFinite(node.y) ? node.y : '?'}`,
    `vx=${Number.isFinite(node.vx) ? Math.round(node.vx) : '?'}`,
    `vy=${Number.isFinite(node.vy) ? Math.round(node.vy) : '?'}`,
    `auto=${node.autoLayout ? '1' : '0'}`,
    `prereqs=${Array.isArray(node.prereqs) ? node.prereqs.join(',') : ''}`
  ];
  return parts.join(' ');
}

function getMedianNumber(values) {
  const nums = (Array.isArray(values) ? values : [])
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value))
    .sort((a, b) => a - b);
  if (nums.length === 0) return null;
  const mid = Math.floor(nums.length / 2);
  if ((nums.length % 2) === 1) return nums[mid];
  return (nums[mid - 1] + nums[mid]) / 2;
}

function collectReachableNonEraTechs({ nodes, byId, dependents, eraNodeIds, reachableTechIds, requiredNodeIds = [] }) {
  const eraSet = new Set(Array.isArray(eraNodeIds) ? eraNodeIds : []);
  const requiredSet = new Set((Array.isArray(requiredNodeIds) ? requiredNodeIds : []).filter((id) => Number.isFinite(id)));
  const hiddenNodes = (Array.isArray(nodes) ? nodes : []).filter((node) => {
    if (!node || !isTechHiddenFromTree(node.entry)) return false;
    if (requiredSet.has(node.id)) return true;
    if (reachableTechIds && !reachableTechIds.has(node.id)) return false;
    return true;
  });
  return hiddenNodes
    .map((node) => {
      const descendantEraIds = new Set();
      const queue = [node.id];
      const visited = new Set([node.id]);
      while (queue.length > 0) {
        const currentId = queue.shift();
        const nextIds = dependents.get(currentId) || [];
        nextIds.forEach((depId) => {
          if (eraSet.has(depId)) descendantEraIds.add(depId);
          if (visited.has(depId)) return;
          const depNode = byId.get(depId);
          if (!depNode) return;
          visited.add(depId);
          queue.push(depId);
        });
      }
      return {
        node,
        descendantEraIds: Array.from(descendantEraIds)
      };
    });
}

function createTechLinkPills({ title, ids, byId, onJump }) {
  const wrap = document.createElement('div');
  wrap.className = 'tech-tree-links';
  const label = document.createElement('strong');
  label.textContent = `${title}:`;
  wrap.appendChild(label);
  const idsList = Array.isArray(ids) ? ids : [];
  if (idsList.length === 0) {
    const none = document.createElement('span');
    none.className = 'hint';
    none.textContent = '(none)';
    wrap.appendChild(none);
    return wrap;
  }
  idsList.forEach((id) => {
    const target = byId.get(id);
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'tech-link-pill';
    const thumb = document.createElement('span');
    thumb.className = 'entry-thumb';
    if (target && target.entry) {
      loadReferenceListThumbnail('technologies', target.entry, thumb);
    }
    const label = document.createElement('span');
    label.textContent = target ? String(target.entry && target.entry.name || `Tech ${id}`) : `Tech ${id}`;
    btn.appendChild(thumb);
    btn.appendChild(label);
    btn.addEventListener('click', () => {
      if (typeof onJump === 'function') onJump(id);
    });
    wrap.appendChild(btn);
  });
  return wrap;
}

function clampTechTreeArrowStyleNumber(value, fallback, min, max) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(min, Math.min(max, n));
}

function rgbToHexColor(color) {
  const toHex = (value) => {
    const n = Math.max(0, Math.min(255, Math.round(Number(value) || 0)));
    return n.toString(16).padStart(2, '0');
  };
  return `#${toHex(color && color.r)}${toHex(color && color.g)}${toHex(color && color.b)}`;
}

function hexColorToRgb(hex, fallback) {
  const text = String(hex || '').trim();
  const match = /^#?([0-9a-f]{6})$/i.exec(text);
  if (!match) return fallback;
  const value = match[1];
  return {
    r: Number.parseInt(value.slice(0, 2), 16),
    g: Number.parseInt(value.slice(2, 4), 16),
    b: Number.parseInt(value.slice(4, 6), 16)
  };
}

